# --- BANKING CORE ---
role BasicAccount { permissions = [check_balance] }

role PersonalBanker extends BasicAccount { permissions = [open_account, deposit_funds] }

role Manager { permissions = [approve_loan] }
role BranchHead extends Manager { permissions = [override_vault] }

role SeniorBanker extends PersonalBanker {
    permissions = [wire_transfer_international]
}

role GuestObserver { permissions = [view_public_info] }

# --- COMPLEX CONFLICTS ---
role Teller { permissions = [handle_cash] }
role Auditor { permissions = [inspect_vault] }

mutex Teller Auditor

user Frank {
    roles = [Teller]
}

user Bob {
    roles = [GuestObserver, PersonalBanker]
}

user Sarah {
    roles = [SeniorBanker]
}

user Alice {
    roles = [BranchHead]
}

user David {
    roles = [Auditor]
}
